import type{CorrectionItem,Flashcard}from'@/types/course'
export interface EngineQuestion{question:string;options:string[];correct:number;explanation:string}
export interface EngineDay{day:number;phase:string;level:string;title:string;goal:string;theory:string;formula:string;conversation:string;transcript:string;vocabulary:Array<[string,string,string]>;errors:CorrectionItem[];translation:{source:string;answer:string};questions:EngineQuestion[];exam?:number}
const q=(question:string,options:string[],correct:number,explanation:string):EngineQuestion=>({question,options,correct,explanation})
const v=(front:string,back:string,hint:string):[string,string,string]=>[front,back,hint]
const e=(incorrect:string,correct:string,explanation:string):CorrectionItem=>({incorrect,correct,explanation})
export const examDays=new Map([[3,1],[6,2],[9,3],[12,4],[16,5],[20,6],[24,7],[28,8],[31,9],[33,10]])
const W=(raw:string):Array<[string,string,string]>=>raw.split(';').map(pair=>{const[front,back]=pair.split('|');return v(front!,back!,`Составьте свой пример с «${front}»`)})
const D=(day:number,phase:string,level:string,title:string,goal:string,theory:string,formula:string,conversation:string,transcript:string,words:string,errors:CorrectionItem[],translation:[string,string],questions:EngineQuestion[]):EngineDay=>({day,phase,level,title,goal,theory,formula,conversation,transcript,vocabulary:W(words),errors,translation:{source:translation[0],answer:translation[1]},questions,exam:examDays.get(day)})
export const englishEngineDays:EngineDay[]=[D(1,'Foundation','A0','Hello, English!','Представиться и понимать базовое приветствие','Английское предложение требует подлежащего. Для имени используем My name is… или I am…. Глагол be связывает человека с именем, страной, профессией или состоянием. В вопросе форма be ставится перед подлежащим.','I am / You are / He is / She is. Am I…? Are you…? Is she…?','Вы знакомитесь с американцем в кофейне. Поздоровайтесь, назовите имя и страну, задайте два ответных вопроса.','Hi! My name is Olivia. I am from Boston, but I live in Austin now. I am a designer. What is your name, and where are you from?','hello|привет;name|имя;country|страна;city|город;live|жить;from|из;student|студент;designer|дизайнер',[e('I from Russia.','I am from Russia.','Перед дополнением с местом нужен be.'),e('You is a student?','Are you a student?','Вопрос: are перед you.'),e('My name Alex.','My name is Alex.','После name нужен is.')],['Меня зовут Анна. Я из Москвы и я начинающий.','My name is Anna. I am from Moscow, and I am a beginner.'],[q('Choose the correct introduction.',['I am Maria.','I Maria.','I is Maria.'],0,'I am + имя.'),q('___ you from Spain?',['Is','Are','Do'],1,'С you используется are.'),q('She ___ a teacher.',['am','are','is'],2,'С she используется is.'),q('Natural question:',['What your name?','What is your name?','What name is you?'],1,'Правильный порядок слов.')]),
D(2,'Foundation','A0','Алфавит, звуки и spelling','Продиктовать имя и различать ключевые звуки','В английском 26 букв и около 44 звуков: название буквы не равно её звуку в слове. Особое внимание русскоязычному ученику нужно уделить /w/ и /v/, /θ/ и /s/, долгим и кратким гласным. При spelling произносим названия букв.','A /eɪ/, E /iː/, I /aɪ/. ship /ɪ/ — sheep /iː/. west /w/ — vest /v/.','Вы регистрируетесь в отеле. Продиктуйте имя и фамилию по буквам, попросите повторить непонятное.','Could you spell your surname, please? Sure. It is Petrov: P-E-T-R-O-V. Did you say V at the end? Yes, V as in Victor.','spell|произнести по буквам;letter|буква;sound|звук;repeat|повторить;surname|фамилия;slowly|медленно;mean|значить;understand|понимать',[e('How it spells?','How do you spell it?','Для вопроса с обычным глаголом нужен do.'),e('Repeat more slow.','Repeat more slowly.','Действие описывает наречие slowly.'),e('I no understand.','I do not understand.','Отрицание Present Simple строится через do not.')],['Пожалуйста, произнесите вашу фамилию по буквам немного медленнее.','Please spell your surname a little more slowly.'],[q('Which word has /iː/?',['ship','sheep','sit'],1,'Sheep содержит долгий /iː/.'),q('Correct request:',['Spell it please?','Could you spell it, please?','You spelling?'],1,'Could you… — вежливая просьба.'),q('The opposite of slowly is ___.',['quickly','quietly','clearly'],0,'Quickly = быстро.'),q('Correct negative:',['I not understand.','I do not understand.','I am not understand.'],1,'Do not + infinitive.')]),
D(3,'Foundation','A0','Числа, возраст, телефон и время','Понимать числа и сообщать личные данные','Числа 13–19 имеют ударение в конце, десятки 30–90 — в начале. Возраст выражается через be, а не have. Для времени используем o’clock, half past, quarter past/to. Номер телефона произносим по цифрам.','I am twenty. It is half past seven. My number is zero seven…','Вы заполняете анкету в языковой школе: возраст, телефон, удобное время занятия.','I am twenty-seven years old. My phone number is zero seven nine, double three, six one five. The best time for me is quarter past six.','number|число;age|возраст;phone|телефон;time|время;half past|половина после;quarter|четверть;morning|утро;evening|вечер',[e('I have 25 years.','I am 25 years old.','Возраст в английском выражается через be.'),e('It is seven and half.','It is half past seven.','Устойчивая модель half past.'),e('My number have…','My number is…','Подлежащее number требует is.')],['Мне двадцать пять лет. Позвоните мне в половине восьмого вечера.','I am twenty-five years old. Call me at half past seven in the evening.'],[q('7:30 is ___.',['half past seven','half to seven','seven quarter'],0,'Half past seven.'),q('Correct age:',['I have thirty years.','I am thirty.','I is thirty.'],1,'Возраст через am.'),q('15 is ___.',['fifty','fifteen','five-teen'],1,'Fifteen.'),q('Exam 1 checks days ___.',['1–3','4–6','all 33'],0,'Первый экзамен закрепляет фундамент.')]),
D(4,'Foundation','A1','Present Simple: мой обычный день','Описывать привычки и задавать вопросы','Present Simple описывает привычки, факты и расписания. С he/she/it глагол получает -s/-es. Отрицание: do not/does not + infinitive. Вопрос: Do/Does + subject + infinitive. После does окончание -s исчезает.','I work. She works. Do you work? She does not work.','Американский коллега спрашивает о вашем распорядке. Расскажите утро, работу и вечер, затем спросите о его привычках.','I usually get up at seven. I make coffee and start work at nine. My brother starts earlier because he works at a hospital. What time do you start work?','usually|обычно;often|часто;sometimes|иногда;always|всегда;never|никогда;start|начинать;finish|заканчивать;routine|распорядок',[e('She work at home.','She works at home.','С she добавляем -s.'),e('Does he works?','Does he work?','После does используется infinitive.'),e('I am go every day.','I go every day.','Для обычного действия be не нужен.')],['Обычно я начинаю работу в девять, но по пятницам заканчиваю раньше.','I usually start work at nine, but on Fridays I finish earlier.'],[q('She ___ at eight.',['start','starts','is start'],1,'С she — starts.'),q('___ you work remotely?',['Are','Do','Does'],1,'Вопрос с обычным глаголом.'),q('He does not ___ coffee.',['drinks','drink','drinking'],1,'После does not — infinitive.'),q('Frequency adverb for 0%:',['always','sometimes','never'],2,'Never = никогда.')]),
D(5,'Foundation','A1','Present Continuous: прямо сейчас','Говорить о текущих и временных действиях','Present Continuous строится как am/is/are + verb-ing. Он нужен для действия в момент речи, временной ситуации и меняющегося процесса. Глаголы состояния know, want, need, understand обычно не используются в Continuous.','I am working. She is studying. Are they waiting?','Вы звоните другу во время поездки. Опишите, где вы, что происходит вокруг и что вы делаете.','I am sitting in a small café near the station. People are talking, and a musician is playing outside. I am waiting for my train.','now|сейчас;currently|в настоящее время;wait|ждать;travel|путешествовать;stay|останавливаться;happen|происходить;outside|снаружи;temporary|временный',[e('I working now.','I am working now.','Нужна форма be.'),e('She is know the answer.','She knows the answer.','Know — глагол состояния.'),e('They are wait.','They are waiting.','После be нужна форма -ing.')],['Сейчас я жду поезд, а мои друзья покупают билеты.','I am waiting for the train now, and my friends are buying tickets.'],[q('Listen! Someone ___.',['sings','is singing','sing'],1,'Действие происходит сейчас.'),q('I ___ what you mean.',['am understanding','understand','understanding'],1,'Understand — stative verb.'),q('We ___ with friends this week.',['stay','are staying','stays'],1,'Временная ситуация.'),q('Correct form:',['She is running.','She running.','She is run.'],0,'Be + verb-ing.')]),
D(6,'Foundation','A1','Вопросы и small talk','Поддерживать короткий разговор с американцем','Small talk строится через открытый вопрос, короткую реакцию и follow-up. В Present Simple используем do/does, с be — меняем порядок без do. Вопросительное слово стоит в начале. Не превращайте разговор в допрос: добавляйте информацию о себе.','Where do you live? What do you do? How are you? Are you new here?','Вы пришли на встречу соседей. Начните разговор о районе, работе и планах на выходные.','Hey, I do not think we have met. I am Chris. I live on the next street. How long have you lived in the neighborhood?','neighborhood|район;weekend|выходные;meet|знакомиться;enjoy|нравиться;nearby|поблизости;recommend|рекомендовать;weather|погода;plan|план',[e('Where you live?','Where do you live?','Нужен do.'),e('What you are doing?','What are you doing?','Be ставится перед подлежащим.'),e('How long you live here?','How long have you lived here?','Для периода до настоящего нужен Present Perfect.')],['Вы давно живёте в этом районе? Что вы обычно делаете по выходным?','Have you lived in this neighborhood for a long time? What do you usually do on weekends?'],[q('Correct question:',['Where do you work?','Where you work?','Where are work?'],0,'Do перед подлежащим.'),q('Follow-up means ___.',['сменить тему','уточняющий вопрос','закончить разговор'],1,'Follow-up развивает ответ.'),q('With be:',['Do you are new?','Are you new?','Does you new?'],1,'Do не нужен.'),q('Exam 2 includes ___.',['only vocabulary','grammar, listening and conversation','no questions'],1,'Экзамен проверяет несколько навыков.')]),
D(7,'Everyday English','A1','Past Simple и вчерашний день','Рассказывать о завершённых событиях','Past Simple описывает законченное прошлое. Правильные глаголы получают -ed, неправильные имеют V2. В отрицании и вопросе используем did + infinitive: форма V2 после did недопустима. Маркеры: yesterday, last, ago, in 2024.','I worked / I went. Did you go? I did not go.','Вы рассказываете знакомому, как прошёл вчерашний день и почему опоздали.','Yesterday I woke up late, missed the bus and walked to work. I arrived twenty minutes late, but my manager understood.','yesterday|вчера;last night|прошлой ночью;ago|назад;wake up|просыпаться;miss|пропустить;arrive|прибыть;leave|уехать;happen|случиться',[e('Did you went?','Did you go?','После did — infinitive.'),e('I buyed it.','I bought it.','Buy — неправильный глагол.'),e('She did not saw him.','She did not see him.','После did not — see.')],['Вчера я опоздал на автобус, поэтому пошёл на работу пешком.','Yesterday I missed the bus, so I walked to work.'],[q('Past of go:',['goed','went','gone'],1,'Go–went–gone.'),q('Did she ___?',['called','call','calls'],1,'После did — call.'),q('Last week we ___ a car.',['buy','bought','have buy'],1,'Завершённое прошлое.'),q('Correct negative:',['I did not see.','I did not saw.','I not saw.'],0,'Did not + infinitive.')]),D(8,'Everyday English','A1','Неправильные глаголы в историях','Освоить V1–V2–V3 через сюжет','Неправильные глаголы нужно учить не алфавитным списком, а семьями и в контексте. V2 используется в Past Simple, V3 — с have и в пассиве. Произнесите три формы вслух и создайте мини-историю.','go–went–gone; see–saw–seen; take–took–taken; write–wrote–written.','Вы рассказываете о неожиданной поездке, используя минимум восемь неправильных глаголов.','Last Saturday, we drove to the coast, saw an empty beach and found a small café. I took photos, wrote a postcard and bought fresh bread.','drive|водить;see|видеть;find|находить;take|брать;write|писать;buy|покупать;bring|приносить;think|думать',[e('We drived there.','We drove there.','Drive–drove–driven.'),e('I have wrote it.','I have written it.','После have нужна V3.'),e('She taked a photo.','She took a photo.','Take–took–taken.')],['Мы поехали к морю, увидели старый маяк и сделали много фотографий.','We drove to the sea, saw an old lighthouse and took many photos.'],[q('V2 of write:',['writed','wrote','written'],1,'Write–wrote–written.'),q('V3 of take:',['took','taken','taked'],1,'Take–took–taken.'),q('Past of bring:',['brought','bringed','brang'],0,'Bring–brought–brought.'),q('Correct sentence:',['We saw it yesterday.','We seen it yesterday.','We have saw it.'],0,'Past Simple использует saw.')]),
D(9,'Everyday English','A1','Past Continuous: фон истории','Соединять длительное и короткое действие','Past Continuous = was/were + -ing. Он создаёт фон или показывает процесс в определённый момент прошлого. Короткое действие в Past Simple часто прерывает его. While обычно вводит длительный процесс, when — событие.','I was driving when she called. While we were eating, it started to rain.','Вы описываете странный момент в городе: что делали люди, когда произошло событие.','I was walking home when all the lights went out. People were leaving the shops, and a dog was barking. Then the lights came back on.','while|пока;when|когда;suddenly|внезапно;light|свет;bark|лаять;walk home|идти домой;go out|погаснуть;come back|вернуться',[e('I was walk.','I was walking.','После was нужна форма -ing.'),e('They was waiting.','They were waiting.','С they — were.'),e('While I cooked, he was calling.','While I was cooking, he called.','Фон — Continuous, событие — Simple.')],['Я шёл домой, когда внезапно погас свет.','I was walking home when the lights suddenly went out.'],[q('I ___ when she called.',['drove','was driving','am driving'],1,'Процесс в прошлом.'),q('They ___ at eight.',['were sleeping','slept always','was sleeping'],0,'They were.'),q('While we were eating, it ___.',['rained suddenly','started to rain','was start'],1,'Короткое событие.'),q('Exam 3 focuses on ___.',['past narratives','future only','articles only'],0,'Третий экзамен проверяет прошлое.')]),
D(10,'Everyday English','A2','Еда, покупки и countable nouns','Заказывать еду и говорить о количестве','Исчисляемые существительные используют a/an и many/few; неисчисляемые — much/little. Some обычно в утверждениях, any в вопросах и отрицаниях. В вежливой просьбе some возможно: Could I have some water?','a sandwich; some water; many apples; much time; a few questions; a little sugar.','Вы заказываете обед в американском кафе, уточняете состав и просите заменить ингредиент.','Could I have the chicken sandwich, please? Does it contain any nuts? I would also like some sparkling water, but no ice.','menu|меню;order|заказывать;contain|содержать;ingredient|ингредиент;some|немного;any|какой-либо;bill|счёт;tip|чаевые',[e('I want a water.','I would like some water.','Water неисчисляемое.'),e('How many sugar?','How much sugar?','С неисчисляемым — much.'),e('There is many bread.','There is a lot of bread.','Bread неисчисляемое.')],['Я хотел бы суп и немного воды без льда.','I would like the soup and some water without ice.'],[q('How ___ apples?',['much','many','a little'],1,'Apples исчисляемое.'),q('Could I have ___ water?',['some','many','an'],0,'В просьбе употребляется some.'),q('Bread is ___.',['countable','uncountable','always plural'],1,'Bread неисчисляемое.'),q('A small number of questions:',['a little','a few','much'],1,'A few + countable plural.')]),
D(11,'Everyday English','A2','Articles: a, an, the, zero','Выбирать артикль по смыслу','A/an вводит один неспецифичный исчисляемый предмет. The указывает на конкретный или уже известный объект, а также уникальные вещи. Нулевой артикль нужен для общих множественных и неисчисляемых понятий. Артикль — это сигнал известности, а не перевод слова.','I saw a dog. The dog was friendly. Dogs are social animals.','Вы описываете новую квартиру: сначала вводите предметы, затем ссылаетесь на них как на известные.','There is a large window in the living room. The window faces a park. The kitchen is small, but it has an excellent view.','apartment|квартира;window|окно;view|вид;living room|гостиная;kitchen|кухня;furniture|мебель;floor|этаж;building|здание',[e('I bought the book yesterday.','I bought a book yesterday.','При первом упоминании — a, если книга не определена.'),e('She is a engineer.','She is an engineer.','Перед гласным звуком — an.'),e('The life is short.','Life is short.','Абстрактное понятие в общем смысле без артикля.')],['В гостиной есть большое окно. Окно выходит на парк.','There is a large window in the living room. The window faces a park.'],[q('First mention: I saw ___ cat.',['a','the','—'],0,'Новый неспецифичный объект.'),q('Second mention: ___ cat was black.',['A','The','An'],1,'Объект уже известен.'),q('She is ___ architect.',['a','an','the always'],1,'Architect начинается с гласного звука.'),q('General statement:',['The books are useful.','Books are useful.','A books are useful.'],1,'Множественное в общем смысле без артикля.')]),
D(12,'Everyday English','A2','Будущее: will, going to, arrangements','Различать решение, намерение и договорённость','Will выражает спонтанное решение, обещание или прогноз-мнение. Be going to — намерение или прогноз по видимым признакам. Present Continuous — уже организованная личная договорённость. Present Simple — официальное расписание.','I will help. I am going to study. I am meeting Sam at six. The train leaves at seven.','Вы планируете выходные с другом: договоритесь о времени, сообщите намерения и примите спонтанное решение.','I am meeting Rachel on Saturday morning. We are going to visit the science museum. The tour starts at ten, so I will book the tickets now.','plan|план;arrangement|договорённость;promise|обещание;probably|вероятно;book|бронировать;visit|посетить;available|свободный;schedule|расписание',[e('I going to call.','I am going to call.','В конструкции нужен be.'),e('I will meeting her.','I will meet her.','После will — infinitive.'),e('The train will leaves.','The train leaves at seven.','Расписание — Present Simple.')],['В субботу я встречаюсь с друзьями. Мы собираемся посетить музей.','I am meeting my friends on Saturday. We are going to visit a museum.'],[q('Spontaneous decision:',['I will answer it.','I am answering yesterday.','I going answer.'],0,'Will для решения в момент речи.'),q('Visible evidence: Look at the clouds!',['It is going to rain.','It rains yesterday.','It will raining.'],0,'Going to для прогноза по признакам.'),q('Fixed arrangement:',['I am meeting Alex at six.','I meet Alex maybe.','I will met Alex.'],0,'Present Continuous.'),q('Exam 4 covers ___.',['A0–A2 foundation','only B2','no grammar'],0,'Это накопительный экзамен.')]),
D(13,'Everyday English','A2','Modal verbs: can, should, must, have to','Выражать способность, совет и обязанность','После модального глагола используется infinitive без to. Can — способность/возможность, should — совет, must — сильная необходимость говорящего, have to — внешнее правило. Must not означает запрет, do not have to — отсутствие необходимости.','You can drive. You should rest. You must not park. You do not have to come.','Друг просит совет перед собеседованием. Объясните, что можно, нужно и не обязательно делать.','You should research the company and prepare examples. You have to arrive on time. You do not have to wear a suit, but you must not look untidy.','ability|способность;advice|совет;rule|правило;necessary|необходимый;prepare|готовиться;arrive|прибыть;wear|носить;allowed|разрешено',[e('You should to go.','You should go.','После should нет to.'),e('You must not to park.','You must not park.','После modal — infinitive.'),e('I can to swim.','I can swim.','После can нет to.')],['Тебе следует подготовиться, но тебе не обязательно надевать костюм.','You should prepare, but you do not have to wear a suit.'],[q('Advice: You ___ rest.',['should','must to','can to'],0,'Should выражает совет.'),q('Prohibition:',['must not','do not have to','could'],0,'Must not = нельзя.'),q('No necessity:',['must not','do not have to','should not always'],1,'Можно не делать.'),q('Correct modal form:',['can swim','can to swim','cans swim'],0,'Modal + infinitive.')]),
D(14,'Everyday English','A2','Present Perfect: опыт и результат','Связывать прошлое с настоящим','Present Perfect = have/has + V3. Он описывает опыт без даты, результат сейчас и незавершённый период. Past Simple отвечает на вопрос когда и требует завершённого времени. Ever, never, already, yet, just часто сочетаются с Perfect.','I have visited Chicago. I went there in 2023. She has just finished.','Вы обсуждаете путешествия: опыт, места, которые ещё не посетили, и последнюю поездку с конкретной датой.','I have visited five countries, but I have never been to Japan. I went to Canada last year and have kept in touch with people I met there.','experience|опыт;ever|когда-либо;never|никогда;already|уже;yet|ещё;just|только что;visit|посетить;keep in touch|поддерживать связь',[e('I have been there yesterday.','I went there yesterday.','Yesterday требует Past Simple.'),e('She has went home.','She has gone home.','После has нужна V3 gone.'),e('Did you ever been?','Have you ever been?','Опыт — Present Perfect.')],['Я никогда не был в Японии, но в прошлом году ездил в Канаду.','I have never been to Japan, but I went to Canada last year.'],[q('Experience without date:',['I have tried it.','I tried it yesterday.','I have try it.'],0,'Present Perfect.'),q('With last year:',['went','have gone','has went'],0,'Finished time.'),q('V3 of go:',['went','gone','goed'],1,'Go–went–gone.'),q('Not finished: I have not done it ___.',['yet','yesterday','ago'],0,'Yet в отрицании.')]),D(15,'Expanding','A2','Present Perfect Continuous','Показывать длительность процесса','Have/has been + verb-ing подчёркивает процесс, начавшийся раньше и продолжающийся сейчас, или его видимый результат. Since обозначает точку начала, for — период. Глаголы состояния обычно остаются в Perfect Simple: have known, have owned.','I have been studying for two hours. I have known her since 2020.','Вы обсуждаете изучение английского: как долго занимаетесь, что изменилось и почему устали.','I have been studying English every day for two weeks. I have learned many useful phrases, but I have also been sleeping less, so I need a better schedule.','since|с какого-то момента;for|в течение;improve|улучшать;practice|практиковаться;recently|недавно;progress|прогресс;focus|сосредоточиться;tired|уставший',[e('I study since Monday.','I have been studying since Monday.','Процесс от прошлого до настоящего.'),e('I have been knowing her.','I have known her.','Know — stative verb.'),e('for 2020','since 2020','Год — точка начала.')],['Я занимаюсь английским каждый день уже две недели.','I have been studying English every day for two weeks.'],[q('A period:',['since two hours','for two hours','at two hours'],1,'For + продолжительность.'),q('A starting point:',['since Monday','for Monday','during Monday'],0,'Since + точка.'),q('Correct stative form:',['have been knowing','have known','am knowing'],1,'Know не используется в Continuous.'),q('Visible result: Why are you wet?',['I have been running.','I ran in 2020.','I run usually.'],0,'Недавний процесс с результатом.')]),
D(16,'Expanding','B1','Comparatives и точные сравнения','Сравнивать варианты и аргументировать выбор','Короткие прилагательные получают -er/-est, длинные — more/most. Much, far, a lot усиливают comparative; slightly и a little смягчают. Конструкция as…as показывает равенство. Less/fewer различают неисчисляемое и исчисляемое.','much better; far more useful; slightly cheaper; as reliable as.','Вы выбираете между двумя курсами английского: сравните цену, гибкость, обратную связь и результат.','The online course is slightly cheaper and far more flexible. However, the evening class offers more speaking practice and fewer distractions.','compare|сравнивать;advantage|преимущество;drawback|недостаток;flexible|гибкий;reliable|надёжный;slightly|немного;far more|намного более;fewer|меньше',[e('more easier','easier','Двойная сравнительная форма невозможна.'),e('much expensive','much more expensive','Much усиливает comparative.'),e('less people','fewer people','People исчисляемое.')],['Онлайн-курс немного дешевле, но вечерний курс намного эффективнее для разговорной практики.','The online course is slightly cheaper, but the evening course is far more effective for speaking practice.'],[q('Correct comparative:',['more easier','easier','easyer'],1,'Easy → easier.'),q('Strong difference:',['very better','much better','most better'],1,'Much + comparative.'),q('Countable: ___ mistakes.',['less','fewer','little'],1,'Fewer + countable.'),q('Exam 5 is ___.',['cumulative','only one lesson','without answers'],0,'Экзамен накапливает материал.')]),
D(17,'Expanding','B1','First и Second Conditionals','Обсуждать реальные планы и гипотезы','First Conditional описывает реальную будущую возможность: if + Present, will + infinitive. Second Conditional — воображаемую или маловероятную ситуацию сейчас/в будущем: if + Past, would + infinitive. В if-clause обычно не ставим will.','If I have time, I will call. If I had more time, I would study.','Друг думает переехать в США. Обсудите реальные шаги и гипотетические варианты жизни.','If you apply early, you will have more options. If I were in your position, I would research the cost of living before choosing a city.','condition|условие;apply|подавать заявку;option|вариант;move|переезжать;afford|позволить себе;opportunity|возможность;decision|решение;research|исследовать',[e('If I will see him, I will tell.','If I see him, I will tell him.','В if-clause First Conditional нет will.'),e('If I would have time…','If I had time…','Second: Past в if-clause.'),e('If I was you…','If I were you…','В совете предпочтительно were.')],['Если у меня будет время, я позвоню. На твоём месте я бы сначала изучил стоимость жизни.','If I have time, I will call. If I were you, I would research the cost of living first.'],[q('Real future: If it rains, we ___.',['will stay home','would stayed','stay yesterday'],0,'First Conditional.'),q('Hypothetical: If I ___ rich…',['am','were','will be'],1,'Second Conditional.'),q('If-clause form:',['If I will know','If I know','If I would know'],1,'Present after if.'),q('Advice formula:',['If I were you…','If I am you…','If I will be you…'],0,'Устойчивая форма совета.')]),
D(18,'Expanding','B1','Gerund и infinitive','Выбирать форму после глагола','Enjoy, avoid, suggest, mind требуют -ing. Want, decide, hope, manage требуют to-infinitive. После stop, remember и try форма меняет смысл: stop doing — прекратить; stop to do — остановиться ради другого действия.','enjoy doing; decide to do; remember to do; remember doing.','Вы обсуждаете привычки обучения: что нравится, чего избегаете, что решили изменить.','I enjoy learning through stories, but I avoid translating every word. I have decided to speak for ten minutes daily and to stop worrying about every mistake.','enjoy|получать удовольствие;avoid|избегать;decide|решать;manage|суметь;suggest|предлагать;remember|помнить;stop|прекращать;mind|возражать',[e('I enjoy to read.','I enjoy reading.','После enjoy — -ing.'),e('We decided leaving.','We decided to leave.','После decide — to-infinitive.'),e('Stop to smoke.','Stop smoking.','Прекратить действие — stop doing.')],['Я решил говорить каждый день и перестать бояться ошибок.','I decided to speak every day and to stop being afraid of mistakes.'],[q('After enjoy:',['to read','reading','read to'],1,'Enjoy doing.'),q('After decide:',['to leave','leaving only','leave to'],0,'Decide to do.'),q('Stop an activity:',['stop doing','stop to do','stop did'],0,'Stop doing.'),q('Do not forget a future action:',['remember doing','remember to do','remember did'],1,'Remember to do.')]),
D(19,'Expanding','B1','Passive Voice','Переносить фокус на действие и результат','Passive = be в нужном времени + V3. Используем, когда исполнитель неизвестен, очевиден или неважен. Время выражает be: is made, was built, has been completed, will be sent, must be checked. By добавляет исполнителя только при необходимости.','Object → subject + be + V3: They built it → It was built.','Вы объясняете процесс производства или рабочую процедуру, фокусируясь на этапах.','First, the application is reviewed. Then the candidate is invited to an interview. A final decision is made within five business days.','process|процесс;review|рассматривать;produce|производить;deliver|доставлять;complete|завершать;decision|решение;stage|этап;require|требовать',[e('The report sent yesterday.','The report was sent yesterday.','Пассив требует be.'),e('It has completed.','It has been completed.','Perfect Passive: has been + V3.'),e('This must checked.','This must be checked.','Modal Passive: modal + be + V3.')],['Заявка рассматривается, после чего кандидата приглашают на собеседование.','The application is reviewed, after which the candidate is invited to an interview.'],[q('Past Passive:',['was sent','sent was','has send'],0,'Was + V3.'),q('Perfect Passive:',['has completed','has been completed','was been complete'],1,'Has been + V3.'),q('Modal Passive:',['must check','must be checked','must been checked'],1,'Modal + be + V3.'),q('Best reason for passive:',['focus on result','always mention actor','avoid all verbs'],0,'Пассив меняет фокус.')]),
D(20,'Expanding','B1','Relative clauses','Соединять идеи без коротких рубленых фраз','Who относится к людям, which — к вещам, whose выражает принадлежность, where — место. Defining clause необходима для идентификации и не имеет запятых. Non-defining добавляет информацию, отделяется запятыми и не использует that.','The person who called. My laptop, which is old, works. A writer whose books…','Вы описываете людей и места, повлиявшие на вашу жизнь.','The teacher who inspired me most was Mr Hall. He worked at a school in Bristol, where I spent two years. His lessons, which were always practical, changed my attitude.','inspire|вдохновлять;influence|влиять;whose|чей;where|где;relationship|отношение;attitude|отношение;support|поддерживать;memorable|запоминающийся',[e('The person which called…','The person who called…','Для человека — who.'),e('My friend, that lives…','My friend, who lives…','В non-defining не используется that.'),e('A man who car…','A man whose car…','Принадлежность — whose.')],['Учитель, который меня вдохновил, работал в школе, где я провёл два года.','The teacher who inspired me worked at the school where I spent two years.'],[q('For people:',['which','who','where'],1,'Who.'),q('Possession:',['whose','who','that is'],0,'Whose.'),q('Place:',['where','which person','whose'],0,'Where.'),q('Exam 6 checks ___.',['B1 sentence building','only numbers','no previous material'],0,'Проверяется построение сложных предложений.')]),
D(21,'Expanding','B1','Reported Speech','Передавать слова, вопросы и просьбы','После глагола сообщения в прошлом обычно происходит backshift: am→was, have done→had done, will→would. В косвенном вопросе порядок слов утвердительный и do/does/did исчезают. Просьба или приказ: ask/tell + object + to-infinitive.','She said she was tired. He asked where I lived. She told me to wait.','Вы пересказываете коллеге важный разговор с менеджером.','Maya said that the deadline had changed. She asked whether I could finish by Friday and told me to contact her if I needed help.','report|сообщать;mention|упоминать;explain|объяснять;ask|спрашивать;tell|говорить кому-то;deadline|срок;change|изменять;contact|связаться',[e('She said me…','She told me… / She said to me…','Tell требует объекта без to; say — с to.'),e('He asked where did I live.','He asked where I lived.','Косвенный вопрос имеет прямой порядок.'),e('She said she will call.','She said she would call.','Will сдвигается в would.')],['Она сказала, что срок изменился, и спросила, смогу ли я закончить к пятнице.','She said that the deadline had changed and asked whether I could finish by Friday.'],[q('Reported will:',['will','would','did'],1,'Will → would.'),q('Correct indirect question:',['where did I live','where I lived','where do I live'],1,'Прямой порядок.'),q('Command:',['told me to wait','said me wait','asked that wait'],0,'Tell + object + to.'),q('Say vs tell:',['said me','told me','told to me always'],1,'Tell принимает объект напрямую.')]),D(22,'Fluency','B1','Phrasal verbs без зубрёжки','Понимать частицы через контекст','Phrasal verb состоит из глагола и частицы, которая меняет смысл. Учите его с объектом и ситуацией: carry out research, put off a meeting, figure out a problem. В разделяемом глаголе местоимение ставится внутрь: turn it down.','figure it out; put the meeting off; carry out research; bring the issue up.','Коллеги обсуждают проблему проекта. Предложите разобраться, не откладывать решение и поднять важный вопрос.','We need to figure out why users are leaving. Let us carry out a short survey and bring the pricing issue up at tomorrow’s meeting. We should not put it off.','figure out|разобраться;put off|отложить;carry out|провести;bring up|поднять тему;turn down|отклонить;look into|изучить;follow up|вернуться с уточнением;set up|организовать',[e('figure out it','figure it out','Местоимение ставится между частями.'),e('discuss about the issue','discuss the issue','Discuss не требует about.'),e('put off to the meeting','put the meeting off','Объект ставится между или после обеих частей.')],['Нам нужно разобраться в причине и не откладывать встречу.','We need to figure out the reason and not put the meeting off.'],[q('Understand/solve:',['figure out','put off','turn down'],0,'Figure out.'),q('Delay:',['carry out','put off','set up'],1,'Put off.'),q('Correct pronoun position:',['turn down it','turn it down','it turn down'],1,'Разделяемый phrasal verb.'),q('Conduct research:',['carry out research','make out research','put research off always'],0,'Carry out.')]),
D(23,'Fluency','B1','Collocations и естественная речь','Заменить дословные сочетания естественными','Collocation — слова, которые носители ожидают вместе. Мы make a decision, meet a deadline, take responsibility, pay attention, raise awareness. Запоминайте сочетание целиком и добавляйте типичный контекст, а не переводите каждое слово отдельно.','make a decision; meet a deadline; take responsibility; highly effective; heavy rain.','Вы обсуждаете результат проекта, используя естественные деловые сочетания.','We met the deadline because the team made several quick decisions and took responsibility for the final result. The campaign also raised awareness of the problem.','decision|решение;deadline|срок;responsibility|ответственность;attention|внимание;awareness|осведомлённость;effort|усилие;result|результат;agreement|соглашение',[e('do a decision','make a decision','С decision употребляется make.'),e('catch a deadline','meet a deadline','Устойчивое сочетание meet a deadline.'),e('strong rain','heavy rain','С rain используется heavy.')],['Команда уложилась в срок и взяла ответственность за результат.','The team met the deadline and took responsibility for the result.'],[q('Natural collocation:',['make a decision','do a decision','build decision'],0,'Make a decision.'),q('Deadline:',['meet','catch','perform'],0,'Meet a deadline.'),q('Rain:',['strong rain','heavy rain','powerful rain'],1,'Heavy rain.'),q('Responsibility:',['take responsibility','make responsibility','do responsible'],0,'Take responsibility.')]),
D(24,'Fluency','B1','Listening: connected speech','Понимать смысл без перевода каждого слова','В естественной речи звуки соединяются, служебные слова редуцируются, а ударные слова несут смысл. Первый проход — тема и отношение говорящего, второй — факты, третий — shadowing. Не открывайте транскрипт до попытки ответить.','gist → details → transcript → shadowing. gonna = going to (разговорно), wanna = want to.','Вы слушаете голосовое сообщение об изменении планов и должны пересказать ключевые детали.','Hi Jamie, it is Laura. We were going to meet at the station at eleven, but engineering work means there are no trains before midday. Could we meet at the Riverside Café at half past twelve instead?','gist|общий смысл;detail|деталь;stress|ударение;reduction|редукция;instead|вместо этого;station|станция;midday|полдень;message|сообщение',[e('listen every word','listen for every word','После listen нужен for/to в зависимости от смысла.'),e('meet in twelve','meet at twelve','С точным временем — at.'),e('There is no trains.','There are no trains.','С множественным — are.')],['Поезда не ходят до полудня, поэтому она предлагает встретиться в кафе в половине первого.','There are no trains before midday, so she suggests meeting at the café at half past twelve.'],[q('Main purpose of the message:',['change a plan','cancel forever','sell tickets'],0,'Говорящий меняет план.'),q('Why no train?',['weather','engineering work','holiday'],1,'Engineering work.'),q('New time:',['11:00','12:30','14:00'],1,'Half past twelve.'),q('Exam 7 emphasizes ___.',['listening plus accumulated grammar','spelling only','no audio'],0,'Комплексная проверка.')]),
D(25,'Fluency','B2','Third и Mixed Conditionals','Обсуждать прошлые альтернативы и последствия','Third Conditional описывает невозможное прошлое: if + had + V3, would have + V3. Mixed Conditional связывает прошлую причину с настоящим результатом или наоборот. Он полезен для анализа решений, но требует ясной временной логики.','If I had known, I would have called. If I had studied more, I would feel confident now.','Вы анализируете неудачное решение проекта: что нужно было сделать иначе и как это влияет сейчас.','If we had tested the idea earlier, we would have found the problem. If we had listened to users, the product would be stronger now.','regret|сожаление;consequence|последствие;alternative|альтернатива;earlier|раньше;prevent|предотвращать;realize|осознавать;outcome|исход;otherwise|иначе',[e('If I would have known…','If I had known…','В if-clause Third Conditional — had + V3.'),e('I would called.','I would have called.','Результат прошлого: would have + V3.'),e('If we knew yesterday…','If we had known yesterday…','Нереальное прошлое требует Past Perfect.')],['Если бы мы протестировали идею раньше, мы бы нашли проблему.','If we had tested the idea earlier, we would have found the problem.'],[q('Third if-clause:',['had known','would know','have knew'],0,'Had + V3.'),q('Third result:',['would have called','would called','will have call'],0,'Would have + V3.'),q('Past cause, present result:',['mixed conditional','zero conditional','imperative'],0,'Это Mixed Conditional.'),q('Correct V3 of know:',['knew','known','knowed'],1,'Know–knew–known.')]),
D(26,'Fluency','B2','Modal deduction','Делать выводы о настоящем и прошлом','Must выражает почти уверенный положительный вывод, might/may/could — возможность, cannot — почти уверенный отрицательный. Для прошлого используем modal + have + V3: must have forgotten, might have left, cannot have seen.','He must be busy. She might be at home. They cannot have known.','Вы пытаетесь объяснить, почему коллега не пришёл на встречу, используя доказательства и степень уверенности.','Daniel is never late, so something must have happened. He might have missed the train, but he cannot have forgotten the meeting because he confirmed it this morning.','evidence|доказательство;certain|уверенный;likely|вероятный;possibly|возможно;miss|пропустить;confirm|подтвердить;forget|забыть;explain|объяснять',[e('He must to be busy.','He must be busy.','После modal нет to.'),e('She might left.','She might have left.','Вывод о прошлом: might have + V3.'),e('He cannot has known.','He cannot have known.','Modal + have + V3.')],['Он, должно быть, пропустил поезд, но он не мог забыть о встрече.','He must have missed the train, but he cannot have forgotten the meeting.'],[q('Strong positive deduction:',['must','might','cannot'],0,'Must.'),q('Past possibility:',['might have left','might left','may has left'],0,'Modal + have + V3.'),q('Strong negative deduction:',['cannot have','must have','should have maybe'],0,'Cannot have.'),q('After modal:',['infinitive','to-infinitive always','past form'],0,'Используется infinitive.')]),
D(27,'Fluency','B2','Formal writing и register','Писать ясный email и менять регистр','Формальный текст имеет ясную цель, нейтральный тон и предсказуемую структуру: opening, reason, details, requested action, closing. Избегайте разговорных сокращений и прямых приказов. Cohesive devices связывают идеи, но не должны перегружать текст.','Dear Ms Lee, I am writing to… Could you please… I would appreciate… Kind regards.','Вы пишете формальное письмо языковой школе: перенос занятия, причина и предложение нового времени.','Dear Ms Lee, I am writing to ask whether it would be possible to move Friday’s lesson. I have a medical appointment at that time. Could we reschedule it for Monday evening? Kind regards, Alex.','formal|формальный;request|просьба;reschedule|перенести;appointment|приём;available|доступный;appreciate|быть признательным;regards|с уважением;possible|возможный',[e('I want move lesson.','I would like to move the lesson.','Would like смягчает просьбу.'),e('Give me another time.','Could we arrange another time?','Формальный запрос не звучит как приказ.'),e('I wait your answer.','I look forward to your reply.','Устойчивое формальное завершение.')],['Я пишу, чтобы попросить перенести пятничное занятие на понедельник.','I am writing to ask whether we could move Friday’s lesson to Monday.'],[q('Formal opening:',['Dear Ms Lee,','Hey Lee!','Yo!'],0,'Dear + title/surname.'),q('Polite request:',['Could you please…','You must…','Give me…'],0,'Could you please.'),q('Formal closing:',['Kind regards,','See ya,','Bye-bye!'],0,'Kind regards.'),q('Register means ___.',['уровень формальности','время глагола','только орфография'],0,'Register — стиль относительно ситуации.')]),
D(28,'Fluency','B2','Opinion essay и аргументация','Строить связный аргумент с примерами','Сильный абзац содержит claim, reason, explanation и example. Introduction переформулирует тему и обозначает позицию; conclusion суммирует без новых аргументов. However и whereas вводят контраст, therefore и as a result — следствие.','Although X, Y. The main reason is… For example… Therefore… On balance…','Вы обсуждаете, может ли ИИ заменить преподавателя языка. Дайте позицию, два аргумента и контраргумент.','AI tools provide immediate practice and feedback. However, a skilled teacher can notice emotional barriers and adapt a long-term plan. On balance, the strongest approach combines both.','claim|тезис;reason|причина;evidence|доказательство;counterargument|контраргумент;whereas|тогда как;therefore|поэтому;on balance|в итоге;combine|сочетать',[e('I am agree.','I agree.','Agree — глагол, be не нужен.'),e('In the other hand…','On the other hand…','Устойчивая связка начинается с on.'),e('Despite it is useful…','Although it is useful… / Despite its usefulness…','После despite не идёт полное предложение без the fact that.')],['Хотя ИИ даёт мгновенную практику, преподаватель лучше видит долгосрочные проблемы.','Although AI provides immediate practice, a teacher is better at identifying long-term problems.'],[q('Contrast linker:',['However','Therefore','In addition'],0,'However.'),q('Result linker:',['Whereas','Therefore','Although'],1,'Therefore.'),q('Strong paragraph contains ___.',['claim and support','random facts','only conclusion'],0,'Тезис нужно развить.'),q('Exam 8 includes ___.',['writing and advanced grammar','only numbers','no feedback'],0,'Комплексный уровень B2.')]),D(29,'B2 Performance','B2','Speaking: extended answer','Говорить 2–3 минуты без заученного текста','Ответ B2 развивается по схеме position → reason → example → qualification → conclusion. Используйте discourse markers для навигации слушателя и fillers, которые дают время подумать: Well, let me think, what I mean is. Исправляйте себя естественно: Sorry, what I meant was…','In my view… The main reason is… For instance… That said… On balance…','Американский собеседник спрашивает, полезно ли жить за границей для изучения языка. Дайте развёрнутый ответ и задайте встречный вопрос.','In my view, living abroad can accelerate learning because you need the language every day. For instance, simple tasks force you to react quickly. That said, immersion only works if you actively speak rather than stay inside your own language group.','fluency|беглость;hesitate|колебаться;clarify|уточнять;point of view|точка зрения;for instance|например;that said|при этом;interaction|взаимодействие;immersion|погружение',[e('From my side…','In my view…','Natural phrase for opinion.'),e('For an example…','For example…','Без артикля an.'),e('It depends from…','It depends on…','Depend сочетается с on.')],['На мой взгляд, погружение работает только тогда, когда ученик активно взаимодействует с людьми.','In my view, immersion only works when the learner actively interacts with people.'],[q('Natural opinion phrase:',['In my view','From my side opinion','On my eyes'],0,'In my view.'),q('Example marker:',['For instance','Despite','Therefore of'],0,'For instance.'),q('Qualification marker:',['That said','Because only','And so but'],0,'That said.'),q('Extended answer needs ___.',['reason and example','only yes/no','memorized list'],0,'Позиция должна быть развита.')]),
D(30,'B2 Performance','B2','Reading и language engine','Делать выводы и замечать авторскую позицию','Skimming даёт тему и структуру, scanning находит факт, inference восстанавливает не сказанный прямо смысл. Смотрите на contrast markers, modal verbs и оценочную лексику. После чтения переводите не слова, а смысловые группы и сохраняйте регистр.','gist → structure → evidence → inference → paraphrase.','Вы обсуждаете короткую статью о дистанционной работе: определите позицию автора и скрытое допущение.','Remote work was once presented as a universal solution. Recent evidence suggests a more complex picture: flexibility can improve focus, whereas isolation may weaken informal learning. The best policy may depend on the team and the task.','evidence|данные;suggest|указывать;whereas|тогда как;isolation|изоляция;weaken|ослаблять;policy|политика;depend on|зависеть от;assumption|допущение',[e('According to me…','In my opinion… / According to the article…','According to не используется с me для мнения.'),e('It depends of the team.','It depends on the team.','Depend on.'),e('Evidence show…','Evidence shows…','Evidence неисчисляемое, согласуется как singular.')],['Данные показывают сложную картину: гибкость улучшает концентрацию, тогда как изоляция может ослаблять обучение.','The evidence suggests a complex picture: flexibility can improve focus, whereas isolation may weaken learning.'],[q('Skimming finds ___.',['overall idea','one phone number','every translation'],0,'Skimming — общий смысл.'),q('Scanning finds ___.',['specific detail','author biography always','grammar only'],0,'Scanning — конкретный факт.'),q('Inference is ___.',['a conclusion from evidence','a copied sentence','a dictionary entry'],0,'Вывод на основе текста.'),q('Whereas signals ___.',['contrast','result','time only'],0,'Whereas — контраст.')]),
D(31,'B2 Performance','B2','Error clinic: русскоязычные ошибки','Диагностировать и исправлять устойчивые ошибки','Ошибки нужно классифицировать: структура предложения, выбор времени, артикль, предлог, collocation или register. Не просто переписывайте правильный вариант: называйте правило и создавайте новый пример. Журнал ошибок превращает слабое место в материал для повторения.','Ошибка → категория → правило → правильный пример → собственный пример через 1, 3 и 7 дней.','Вы преподаватель: объясните американцу, почему русскоязычные ученики говорят I am agree, depend from и feel myself.','Russian speakers often add be before ordinary verbs because Russian structures work differently. For example, we say I agree, not I am agree, and I feel tired, not I feel myself tired.','classify|классифицировать;pattern|закономерность;article|артикль;preposition|предлог;collocation|сочетание;register|регистр;review|повторять;correct|исправлять',[e('I am agree.','I agree.','Agree — обычный глагол.'),e('It depends from you.','It depends on you.','Dependent preposition: on.'),e('I feel myself tired.','I feel tired.','Возвратное местоимение здесь не нужно.')],['Я согласен, что это зависит от ситуации, но сейчас я чувствую себя уставшим.','I agree that it depends on the situation, but I feel tired now.'],[q('Correct:',['I agree.','I am agree.','I agreeing.'],0,'Agree — verb.'),q('Correct preposition:',['depends on','depends from','depends of'],0,'Depend on.'),q('Natural phrase:',['I feel tired.','I feel myself tired.','I am feel tired.'],0,'Feel + adjective.'),q('Exam 9 is mainly a ___.',['diagnostic error clinic','spelling game only','lesson without feedback'],0,'Он выявляет устойчивые ошибки.')]),
D(32,'B2 Performance','B2','Integrated simulation','Объединить listening, speaking, writing и translation','На реальном уровне навыки не разделены: вы слушаете, делаете заметки, отвечаете, уточняете и пишете follow-up. Используйте стратегию: определить задачу, выбрать регистр, собрать 3–5 ключевых идей, выполнить, затем проверить точность и связность.','task → audience → register → key ideas → response → accuracy check.','Симуляция: вы услышали изменение проекта, должны уточнить детали устно и отправить краткое итоговое письмо.','The client has moved the launch to the fifteenth. They need the revised presentation by Monday and would like us to include the latest survey results. Please confirm who can update the slides.','launch|запуск;revise|перерабатывать;survey|опрос;confirm|подтверждать;include|включать;update|обновлять;summary|краткое резюме;follow-up|последующее сообщение',[e('The client moved launch on fifteen.','The client has moved the launch to the fifteenth.','Нужны артикль, ordinal и предлог to.'),e('They want that we include…','They would like us to include…','Would like + object + to.'),e('Who can updates?','Who can update?','После modal — infinitive.')],['Клиент перенёс запуск на пятнадцатое и попросил включить последние результаты опроса.','The client has moved the launch to the fifteenth and asked us to include the latest survey results.'],[q('After can:',['update','updates','to updating'],0,'Modal + infinitive.'),q('Polite client request:',['would like us to','wants that we','want us we'],0,'Would like + object + to.'),q('Project change with current result:',['has moved','move yesterday','has move'],0,'Present Perfect.'),q('Integrated task requires ___.',['multiple skills','only vocabulary','no checking'],0,'Навыки работают вместе.')]),
D(33,'B2 Performance','B2','Final Exam 10 · English Engine','Показать независимое владение системой языка','Финальный день проверяет не запоминание ответов, а перенос навыка. Перед началом сформулируйте правила без подсказок, затем выполните listening, grammar, translation, speaking и writing. После проверки создайте план на следующие 30 дней из трёх слабых зон.','Recall → perform → check → classify errors → next plan.','Финальный разговор: обсудите, как изменился ваш английский за 33 дня, приведите доказательства и обозначьте следующий шаг.','Thirty-three days ago, I hesitated before every sentence. Now I can explain an opinion, understand the main point of a natural message and notice many of my own errors. I still need to expand my vocabulary and practise listening daily.','achievement|достижение;evidence|доказательство;improve|улучшать;weakness|слабая сторона;strength|сильная сторона;independent|самостоятельный;continue|продолжать;reflect|осмысливать',[e('My English became more better.','My English has become much better.','Present Perfect + корректная comparative.'),e('I can to explain.','I can explain.','После can нет to.'),e('I need practice more.','I need to practise more.','Need to + infinitive.')],['За 33 дня я научился объяснять своё мнение, понимать основную мысль и замечать собственные ошибки.','In 33 days, I have learned to explain my opinion, understand the main idea and notice my own mistakes.'],[q('Correct progress statement:',['I have improved.','I am improve.','I have improve.'],0,'Have + V3.'),q('After can:',['explain','to explain','explained'],0,'Can + infinitive.'),q('Next step should target ___.',['three diagnosed weaknesses','random lessons','nothing after day 33'],0,'План строится по ошибкам.'),q('The honest outcome is ___.',['a strong system and path toward B2','automatic native fluency','no need for practice'],0,'33 дня создают интенсивную систему, но язык требует продолжения.')])
]

export function buildSpacedCards(dayIndex:number):Flashcard[]{const indexes=[dayIndex,dayIndex-1,dayIndex-3,dayIndex-7].filter(index=>index>=0);const cards:Flashcard[]=[];for(const index of indexes){for(const[word,translation,hint]of englishEngineDays[index]!.vocabulary){if(!cards.some(card=>card.front===word))cards.push({front:word,back:translation,hint});if(cards.length===20)return cards}}for(const day of englishEngineDays){for(const[word,translation,hint]of day.vocabulary){if(!cards.some(card=>card.front===word))cards.push({front:word,back:translation,hint});if(cards.length===20)return cards}}return cards}
export const englishEnginePhases=[{title:'Фаза 1 · Запуск системы',range:[1,6],level:'A0 → A1'},{title:'Фаза 2 · Повседневный английский',range:[7,14],level:'A1 → A2'},{title:'Фаза 3 · Расширение речи',range:[15,21],level:'A2 → B1'},{title:'Фаза 4 · Беглость и точность',range:[22,28],level:'B1 → B2 topics'},{title:'Фаза 5 · B2 Performance',range:[29,33],level:'B2 practice'}]